 Begin SlaMap 	# Conversion between sky coordinate systems
    Nin = 2 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    Nsla = 2 	# Number of conversion steps
    Sla1 = "EQHE" 	# Equatorial to helio-ecliptic
    Sla1a = 51544 	# Modified Julian Date of observation
    Sla2 = "HEEQ" 	# Helio-ecliptic to equatorial
    Sla2a = 51544 	# Modified Julian Date of observation
 End SlaMap
